import{_ as s,C as o,o as n,c as r,a2 as a,E as i}from"./chunks/framework.BKG_UbFK.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"en/features/dashboard.md","filePath":"en/features/dashboard.md"}'),d={name:"en/features/dashboard.md"};function l(h,e,c,u,p,m){const t=o("Screenshot");return n(),r("div",null,[e[0]||(e[0]=a('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>The Dashboard is the landing page of the Clearance panel. It gives an at-a-glance summary of the authorization state of your application - no configuration required.</p><h2 id="what-it-shows" tabindex="-1">What it shows <a class="header-anchor" href="#what-it-shows" aria-label="Permalink to &quot;What it shows&quot;">​</a></h2><ul><li><strong>Total roles</strong> - count of all Spatie roles.</li><li><strong>Total guards</strong> - count of all guards managed by Clearance (see <a href="/clearance-docs/en/features/guards.html">Guards</a>).</li><li><strong>Total permissions</strong> - count of all Spatie permissions.</li><li><strong>Permission groups</strong> - the number of distinct permission groups, derived from the naming prefix (the <code>group</code> in <code>group-action</code>, e.g. <code>orders</code> in <code>orders-create</code>). See <a href="/clearance-docs/en/features/permissions.html">Permissions</a> for the naming convention.</li><li><strong>Contextual role assignments</strong> - the number of role assignments scoped to a specific model instance (a Store, a Tenant, a Project). See <a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a>.</li><li><strong>Top 5 roles by user count</strong> - the five roles with the most assigned users, ranked.</li></ul>',4)),i(t,{src:"/screenshots/dashboard-page.png",alt:"Clearance Dashboard showing role, guard, and permission counts",caption:"The Dashboard summarizes roles, guards, permissions, groups, contextual assignments, and top roles."}),e[1]||(e[1]=a('<h2 id="accessing-the-dashboard" tabindex="-1">Accessing the Dashboard <a class="header-anchor" href="#accessing-the-dashboard" aria-label="Permalink to &quot;Accessing the Dashboard&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Route name</th><th>Description</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>Dashboard</td></tr></tbody></table><p>Reading the Dashboard requires the <code>clearance-access</code> permission, same as every other panel section. See <a href="/clearance-docs/en/features/super-admin.html#panel-access-fine-grained-write-permissions">Super Admin</a> for the full access-control table.</p><h2 id="embedding-the-component" tabindex="-1">Embedding the component <a class="header-anchor" href="#embedding-the-component" aria-label="Permalink to &quot;Embedding the component&quot;">​</a></h2><p>The Dashboard is a self-contained Livewire component. Mount it anywhere in your own layouts instead of - or in addition to - the pre-built <code>/clearance</code> route:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/clearance-docs/en/features/permissions.html">Permissions</a> - manage the permission list feeding the Dashboard&#39;s counts.</li><li><a href="/clearance-docs/en/features/roles.html">Roles</a> - manage the roles behind the &quot;top 5 by user count&quot; stat.</li><li><a href="/clearance-docs/en/features/contextual-authorization.html">Contextual Authorization</a> - what a contextual role assignment is.</li></ul>',8))])}const f=s(d,[["render",l]]);export{b as __pageData,f as default};
